    """Return the layout equivalent to applying layoutB, then layoutA."""
    # Case 1: layoutB is None - return layoutA unchanged
    if layoutB is None:
        return layoutA

    # Case 2: layoutB is an integer - treat as Layout(layoutB)
    if is_int(layoutB):
        layoutB = Layout(layoutB)

    # Case 3: layoutB is a tuple - compose each mode of layoutA with matching entry
    if is_tuple(layoutB):
        if is_tuple(layoutA.shape):
            results = []
            for i, entry in enumerate(layoutB):
                if entry is None:
                    results.append(layoutA[i])
                elif is_int(entry):
                    results.append(composition(layoutA[i], Layout(entry)))
                elif is_layout(entry):
                    results.append(composition(layoutA[i], entry))
            return make_layout(tuple(results))
        else:
            # A is not hierarchical, B is a tuple with one entry
            assert len(layoutB) == 1
            entry = layoutB[0]
            if entry is None:
                return layoutA
            elif is_int(entry):
                return composition(layoutA, Layout(entry))
            elif is_layout(entry):
                return composition(layoutA, entry)

    # Now layoutB is a Layout
    flat_stride_B = flatten(layoutB.stride)

    # Case: stride-zero layoutB - return stride-zero layout with layoutB.shape
    if all(s == 0 for s in flat_stride_B):
        zero_stride = tuple(0 for _ in flatten(layoutB.shape))
        if is_tuple(layoutB.shape):
            return Layout(layoutB.shape, zero_stride)
        return Layout(layoutB.shape, 0)

    # General case: use coalesced modes of layoutA
    coA = coalesce(layoutA)
    flat_shape_A = flatten(coA.shape)
    flat_stride_A = flatten(coA.stride)
    flat_shape_B = flatten(layoutB.shape)

    # Get the coalesced stride of A (first mode's stride after coalescing)
    D_A = flat_stride_A[0] if flat_stride_A else 1

    if len(flat_shape_B) == 1:
        # B is 1D, compose with coalesced A
        S_B = flat_shape_B[0]
        D_B = flat_stride_B[0]
        R_stride = D_B * D_A
        return Layout(S_B, R_stride)
    else:
        # B is multi-dimensional, compose each mode with coalesced A
        results = []
        for i in range(len(flat_shape_B)):
            S_Bi = flat_shape_B[i]
            D_Bi = flat_stride_B[i]
            R_stride_i = D_Bi * D_A
            results.append(Layout(S_Bi, R_stride_i))
        return make_layout(tuple(results))

